"""Recursive-descent parser for the expression language.

Grammar (simplified):
  program    = stmt*
  stmt       = let_stmt | expr_stmt
  let_stmt   = LET IDENT EQ expr SEMICOLON
  expr_stmt  = expr SEMICOLON
  expr       = comparison
  comparison = additive (EQEQ additive)?
  additive   = term ((PLUS | MINUS) term)*      -- BUG: should be separate from term
  term       = unary ((STAR | SLASH) unary)*    -- BUG: term is never called from additive
  unary      = (MINUS unary) | primary          -- BUG: double unary parses wrong
  primary    = NUMBER | STRING | IDENT | call_expr | fn_expr | LPAREN expr RPAREN

All parse bugs live here and in the precedence table.
"""
from __future__ import annotations
from dataclasses import dataclass, field
from typing import List, Optional, Any

from .lexer import (
    Token, NUMBER, STRING, IDENT, PLUS, MINUS, STAR, SLASH,
    EQ, EQEQ, LPAREN, RPAREN, LBRACE, RBRACE, COMMA, SEMICOLON,
    LET, FN, CALL, EOF
)


# ---------------------------------------------------------------------------
# AST node types
# ---------------------------------------------------------------------------

@dataclass
class NumberNode:
    value: float

@dataclass
class StringNode:
    value: str   # raw value from lexer (escapes NOT processed here)

@dataclass
class IdentNode:
    name: str

@dataclass
class BinOpNode:
    op: str
    left: Any
    right: Any

@dataclass
class NegateNode:
    operand: Any

@dataclass
class LetNode:
    name: str
    value: Any

@dataclass
class FnNode:
    params: List[str]
    body: List[Any]

@dataclass
class CallNode:
    callee: Any
    args: List[Any]

@dataclass
class ProgramNode:
    stmts: List[Any]


class ParseError(Exception):
    pass


# ---------------------------------------------------------------------------
# Parser
# ---------------------------------------------------------------------------

class Parser:
    def __init__(self, tokens: List[Token]) -> None:
        self._tokens = tokens
        self._pos = 0

    # -- helpers ------------------------------------------------------------

    def _peek(self) -> Token:
        return self._tokens[self._pos]

    def _advance(self) -> Token:
        tok = self._tokens[self._pos]
        self._pos += 1
        return tok

    def _expect(self, type_: str) -> Token:
        tok = self._peek()
        if tok.type != type_:
            raise ParseError(
                f"Expected {type_!r} but got {tok.type!r} ({tok.value!r}) at pos {tok.pos}"
            )
        return self._advance()

    def _match(self, *types: str) -> bool:
        return self._peek().type in types

    # -- public entry -------------------------------------------------------

    def parse(self) -> ProgramNode:
        stmts = []
        while not self._match(EOF):
            stmts.append(self._stmt())
        return ProgramNode(stmts)

    # -- statements ---------------------------------------------------------

    def _stmt(self) -> Any:
        if self._match(LET):
            return self._let_stmt()
        node = self._expr()
        self._expect(SEMICOLON)
        return node

    def _let_stmt(self) -> LetNode:
        self._expect(LET)
        name = self._expect(IDENT).value
        self._expect(EQ)
        val = self._expr()
        self._expect(SEMICOLON)
        return LetNode(name, val)

    # -- expressions --------------------------------------------------------

    def _expr(self) -> Any:
        return self._comparison()

    def _comparison(self) -> Any:
        left = self._additive()
        if self._match(EQEQ):
            op = self._advance().value
            right = self._additive()
            return BinOpNode(op, left, right)
        return left

    def _additive(self) -> Any:
        # BUG: calls _additive_term instead of a real _term, so * and / have
        # the SAME precedence as + and -.  We never call the real _term level.
        left = self._additive_term()
        while self._match(PLUS, MINUS, STAR, SLASH):
            op = self._advance().value
            right = self._additive_term()
            left = BinOpNode(op, left, right)
        return left

    def _additive_term(self) -> Any:
        """This is really just 'unary' — the true _term level is bypassed."""
        return self._unary()

    def _unary(self) -> Any:
        if self._match(MINUS):
            self._advance()
            # BUG: for '--5' we consume one MINUS here, then recurse into
            # _primary (not _unary), so the second MINUS is never parsed as
            # a negation — it will cause a ParseError or wrong result.
            operand = self._primary()
            return NegateNode(operand)
        return self._primary()

    # -- primary ------------------------------------------------------------

    def _primary(self) -> Any:
        tok = self._peek()

        if tok.type == NUMBER:
            self._advance()
            return NumberNode(float(tok.value))

        if tok.type == STRING:
            self._advance()
            return StringNode(tok.value)  # raw escape sequences preserved

        if tok.type == IDENT:
            self._advance()
            return IdentNode(tok.value)

        if tok.type == CALL:
            return self._call_expr()

        if tok.type == FN:
            return self._fn_expr()

        if tok.type == LPAREN:
            self._advance()
            node = self._expr()
            self._expect(RPAREN)
            return node

        raise ParseError(
            f"Unexpected token {tok.type!r} ({tok.value!r}) at pos {tok.pos}"
        )

    def _call_expr(self) -> CallNode:
        self._expect(CALL)
        self._expect(LPAREN)
        callee = self._expr()
        args = []
        if not self._match(RPAREN):
            self._expect(COMMA)
            while not self._match(RPAREN):
                args.append(self._expr())
                if self._match(COMMA):
                    self._advance()
        self._expect(RPAREN)
        return CallNode(callee, args)

    def _fn_expr(self) -> FnNode:
        self._expect(FN)
        self._expect(LPAREN)
        params = []
        while not self._match(RPAREN):
            params.append(self._expect(IDENT).value)
            if self._match(COMMA):
                self._advance()
        self._expect(RPAREN)
        self._expect(LBRACE)
        body = []
        while not self._match(RBRACE):
            body.append(self._stmt())
        self._expect(RBRACE)
        return FnNode(params, body)


def parse(source: str) -> ProgramNode:
    """Convenience: lex + parse *source*, return AST."""
    from .lexer import tokenize
    tokens = tokenize(source)
    return Parser(tokens).parse()

seed_files.expr_lang/evaluator.py:
"""AST evaluator for the expression language.

Walks the AST produced by parser.py and returns Python values.
Supported types: float, str, bool, callable (FnNode closures).

Bugs in this file:
  - StringNode: does NOT unescape the raw value from the lexer.  The quotes
    were already stripped by the lexer, but backslash sequences are literal.
  - Comparison (==): does NOT call runtime.coerce() before comparing.
  - runtime.coerce() itself returns string "true"/"false" instead of bool.
"""
from __future__ import annotations
from typing import Any, Dict, List

from .parser import (
    ProgramNode, NumberNode, StringNode, IdentNode,
    BinOpNode, NegateNode, LetNode, FnNode, CallNode
)


class EvalError(Exception):
    pass


class Evaluator:
    def __init__(self, runtime: Any) -> None:
        self._runtime = runtime

    def eval_program(self, node: ProgramNode, env: Dict[str, Any]) -> Any:
        result = None
        for stmt in node.stmts:
            result = self.eval_node(stmt, env)
        return result

    def eval_node(self, node: Any, env: Dict[str, Any]) -> Any:
        if isinstance(node, NumberNode):
            return node.value

        if isinstance(node, StringNode):
            # BUG: raw escape sequences are NOT processed.
            # Should call: return node.value.replace('\\"', '"').replace('\\\\', '\\') etc.
            # Instead we return the raw string with backslashes intact.
            return node.value

        if isinstance(node, IdentNode):
            return self._runtime.lookup(node.name, env)

        if isinstance(node, LetNode):
            val = self.eval_node(node.value, env)
            env[node.name] = val
            return val

        if isinstance(node, NegateNode):
            val = self.eval_node(node.operand, env)
            if not isinstance(val, (int, float)):
                raise EvalError(f"Cannot negate non-numeric value: {val!r}")
            return -val

        if isinstance(node, BinOpNode):
            return self._eval_binop(node, env)

        if isinstance(node, FnNode):
            # Capture current env as closure (shallow copy)
            captured = dict(env)
            return ("__fn__", node, captured)

        if isinstance(node, CallNode):
            callee = self.eval_node(node.callee, env)
            args = [self.eval_node(a, env) for a in node.args]
            return self._runtime.call(callee, args, env, self)

        raise EvalError(f"Unknown AST node: {type(node).__name__}")

    def _eval_binop(self, node: BinOpNode, env: Dict[str, Any]) -> Any:
        left = self.eval_node(node.left, env)
        right = self.eval_node(node.right, env)
        op = node.op

        if op == "+":
            if isinstance(left, str) or isinstance(right, str):
                return str(left) + str(right)
            return left + right
        if op == "-":
            return left - right
        if op == "*":
            return left * right
        if op == "/":
            if right == 0:
                raise EvalError("Division by zero")
            return left / right
        if op == "==":
            # BUG: should call self._runtime.coerce(left, right) first so that
            # "5" == 5 evaluates to True.  Instead we do strict Python comparison.
            return left == right

        raise EvalError(f"Unknown binary operator: {op!r}")

seed_files.expr_lang/runtime.py:
"""Runtime environment for the expression language.

Provides:
  - Variable lookup / assignment with scope support
  - Built-in functions: print, len, str, num, type_of
  - Type coercion rules for the == operator
  - Function call dispatch (creates a NEW scope)

Bugs in this file:
  - call(): uses the CALLER's env dict directly instead of creating a new
    child scope.  Variables set inside the function body leak back to the
    caller.
  - coerce(): returns the string "true" / "false" instead of Python bool
    True / False.
"""
from __future__ import annotations
from typing import Any, Dict, List, Tuple


class RuntimeError_(Exception):
    """Runtime error (using a different name to avoid shadowing built-in)."""
    pass


# Built-in function registry
_BUILTINS: Dict[str, Any] = {}


def _builtin(name: str):
    def decorator(fn):
        _BUILTINS[name] = fn
        return fn
    return decorator


@_builtin("print")
def _print(*args):
    print(*args)
    return args[-1] if args else None


@_builtin("len")
def _len(val):
    try:
        return float(len(val))
    except TypeError:
        raise RuntimeError_(f"len() not supported for {type(val).__name__}")


@_builtin("str")
def _str(val):
    return str(val)


@_builtin("num")
def _num(val):
    try:
        return float(val)
    except (ValueError, TypeError):
        raise RuntimeError_(f"Cannot convert {val!r} to number")


@_builtin("type_of")
def _type_of(val):
    if isinstance(val, bool):
        return "bool"
    if isinstance(val, float):
        return "number"
    if isinstance(val, str):
        return "string"
    if isinstance(val, tuple) and val and val[0] == "__fn__":
        return "function"
    return "unknown"


class Runtime:
    """Stateless helper — env dicts are passed explicitly."""

    def lookup(self, name: str, env: Dict[str, Any]) -> Any:
        if name in env:
            return env[name]
        if name in _BUILTINS:
            return ("__builtin__", name)
        raise RuntimeError_(f"Undefined variable: {name!r}")

    def call(
        self,
        callee: Any,
        args: List[Any],
        caller_env: Dict[str, Any],
        evaluator: Any,
    ) -> Any:
        # Built-in functions
        if isinstance(callee, tuple) and callee[0] == "__builtin__":
            fn = _BUILTINS[callee[1]]
            return fn(*args)

        # User-defined functions
        if isinstance(callee, tuple) and callee[0] == "__fn__":
            _, fn_node, closure = callee
            # BUG: We reuse caller_env directly instead of creating a new scope.
            # Any `let` inside the function body will mutate caller_env.
            fn_env = caller_env          # should be: fn_env = dict(closure)
            for param, arg in zip(fn_node.params, args):
                fn_env[param] = arg
            result = None
            for stmt in fn_node.body:
                result = evaluator.eval_node(stmt, fn_env)
            return result

        raise RuntimeError_(f"Cannot call {callee!r}: not a function")

    def coerce(self, left: Any, right: Any) -> Tuple[Any, Any]:
        """Coerce left and right to a common type for comparison.

        Rules:
          - If one is str and the other is a number, convert number to str.
          - Otherwise return as-is.

        BUG: returns string "true"/"false" instead of bool True/False.
        This method is never called by evaluator.py anyway (another bug).
        """
        if isinstance(left, str) and isinstance(right, float):
            # Try numeric coercion: if left can be parsed as a number, compare numerically
            try:
                return float(left), right
            except ValueError:
                return left, str(right)
        if isinstance(left, float) and isinstance(right, str):
            try:
                return left, float(right)
            except ValueError:
                return str(left), right
        # BUG: should just return (left, right) and let the caller decide.
        # Instead, we return string sentinels for booleans.
        if isinstance(left, bool):
            return ("true" if left else "false"), right
        if isinstance(right, bool):
            return left, ("true" if right else "false")
        return left, right
